// ─── Domain Types ────────────────────────────────────────────────────────────

export type SeatStatus = "available" | "reserved";

export interface Seat {
  id: string;
  status: SeatStatus;
}

export interface Reservation {
  seatId: string;
  userId: string;
  reservedAt: Date;
}

export interface Database {
  findSeat(seatId: string): Promise<Seat | null>;
  updateSeatStatus(
    seatId: string,
    status: string,
    userId: string,
    expectedCurrentStatus: string
  ): Promise<boolean>;
}

// ─── Error Constants ─────────────────────────────────────────────────────────

export class ReservationError extends Error {
  constructor(
    public readonly code: "SEAT_NOT_FOUND" | "SEAT_ALREADY_RESERVED",
    message: string
  ) {
    super(message);
    this.name = "ReservationError";
  }
}

export const SEAT_NOT_FOUND = "SEAT_NOT_FOUND" as const;
export const SEAT_ALREADY_RESERVED = "SEAT_ALREADY_RESERVED" as const;

// ─── Implementation ───────────────────────────────────────────────────────────

/**
 * Reserves a seat for a user.
 *
 * Uses optimistic locking via `updateSeatStatus` to handle concurrent calls
 * safely: if two callers read the same "available" seat simultaneously, only
 * the first `updateSeatStatus` will succeed (expectedCurrentStatus matches);
 * the second will receive `false` and throw SEAT_ALREADY_RESERVED.
 *
 * @throws {ReservationError} SEAT_NOT_FOUND       — seat does not exist
 * @throws {ReservationError} SEAT_ALREADY_RESERVED — seat is taken or lost a
 *                                                    concurrency race
 */
export async function reserveSeat(
  seatId: string,
  userId: string,
  db: Database
): Promise<Reservation> {
  // AC4: seat must exist
  const seat = await db.findSeat(seatId);
  if (seat === null) {
    throw new ReservationError(SEAT_NOT_FOUND, `Seat '${seatId}' not found`);
  }

  // AC2: seat must be available
  if (seat.status !== "available") {
    throw new ReservationError(
      SEAT_ALREADY_RESERVED,
      `Seat '${seatId}' is already reserved`
    );
  }

  // AC1 + AC3: attempt atomic transition via optimistic locking.
  // If another caller reserved the seat between our findSeat and this call,
  // updateSeatStatus returns false because the current status no longer matches
  // the expectedCurrentStatus we recorded ("available").
  const updated = await db.updateSeatStatus(
    seatId,
    "reserved",
    userId,
    seat.status // expectedCurrentStatus = "available"
  );

  if (!updated) {
    // Lost the concurrency race — another reservation won
    throw new ReservationError(
      SEAT_ALREADY_RESERVED,
      `Seat '${seatId}' was reserved by another request`
    );
  }

  return {
    seatId,
    userId,
    reservedAt: new Date(),
  };
}

