import {
  reserveSeat,
  Database,
  Seat,
  Reservation,
  ReservationError,
  SEAT_NOT_FOUND,
  SEAT_ALREADY_RESERVED,
} from "./reserveSeat";

// ─── Helpers ──────────────────────────────────────────────────────────────────

function makeSeat(id: string, status: "available" | "reserved"): Seat {
  return { id, status };
}

/**
 * Builds a mock Database.
 *
 * @param seat         The seat findSeat resolves to (null = not found)
 * @param updateResult What updateSeatStatus returns (default: true)
 */
function makeDb(
  seat: Seat | null,
  updateResult = true,
  updateSpy?: jest.Mock
): Database {
  const updateFn = updateSpy ?? jest.fn().mockResolvedValue(updateResult);
  return {
    findSeat: jest.fn().mockResolvedValue(seat),
    updateSeatStatus: updateFn,
  };
}

// ─── AC1: Happy path ─────────────────────────────────────────────────────────

describe("AC1 — available seat is reserved and reservation is returned", () => {
  it("returns a Reservation with correct seatId and userId", async () => {
    const db = makeDb(makeSeat("A1", "available"));

    const reservation = await reserveSeat("A1", "user-42", db);

    expect(reservation.seatId).toBe("A1");
    expect(reservation.userId).toBe("user-42");
    expect(reservation.reservedAt).toBeInstanceOf(Date);
  });

  it("calls updateSeatStatus with status='reserved' and expectedCurrentStatus='available'", async () => {
    const updateSpy = jest.fn().mockResolvedValue(true);
    const db = makeDb(makeSeat("A1", "available"), true, updateSpy);

    await reserveSeat("A1", "user-42", db);

    expect(updateSpy).toHaveBeenCalledTimes(1);
    expect(updateSpy).toHaveBeenCalledWith("A1", "reserved", "user-42", "available");
  });
});

// ─── AC2: Already reserved ────────────────────────────────────────────────────

describe("AC2 — already-reserved seat throws SEAT_ALREADY_RESERVED", () => {
  it("throws ReservationError with code SEAT_ALREADY_RESERVED", async () => {
    const db = makeDb(makeSeat("A1", "reserved"));

    await expect(reserveSeat("A1", "user-42", db)).rejects.toThrow(
      ReservationError
    );
    await expect(reserveSeat("A1", "user-42", db)).rejects.toMatchObject({
      code: SEAT_ALREADY_RESERVED,
    });
  });

  it("does NOT call updateSeatStatus when seat is already reserved", async () => {
    const updateSpy = jest.fn();
    const db = makeDb(makeSeat("A1", "reserved"), true, updateSpy);

    await expect(reserveSeat("A1", "user-42", db)).rejects.toThrow();
    expect(updateSpy).not.toHaveBeenCalled();
  });
});

// ─── AC3: Concurrency — optimistic locking ────────────────────────────────────

describe("AC3 — concurrent calls: exactly one succeeds, one throws SEAT_ALREADY_RESERVED", () => {
  it("throws SEAT_ALREADY_RESERVED when updateSeatStatus returns false (lost the race)", async () => {
    // Simulates: two callers both read "available", but only the first write wins.
    // Our call is the loser — updateSeatStatus returns false.
    const db = makeDb(makeSeat("A1", "available"), false);

    await expect(reserveSeat("A1", "user-99", db)).rejects.toMatchObject({
      code: SEAT_ALREADY_RESERVED,
    });
  });

  it("exactly one of two concurrent calls succeeds when they race on the same seat", async () => {
    // We simulate two concurrent callers sharing one seat record.
    // updateSeatStatus uses a counter to let the first call win and the second lose.
    let writeCount = 0;
    const seat = makeSeat("A1", "available");

    const racingDb: Database = {
      findSeat: jest.fn().mockResolvedValue(seat),
      updateSeatStatus: jest.fn().mockImplementation(async () => {
        writeCount += 1;
        return writeCount === 1; // first wins, subsequent lose
      }),
    };

    const [result1, result2] = await Promise.allSettled([
      reserveSeat("A1", "user-1", racingDb),
      reserveSeat("A1", "user-2", racingDb),
    ]);

    const fulfilled = [result1, result2].filter((r) => r.status === "fulfilled");
    const rejected = [result1, result2].filter((r) => r.status === "rejected");

    expect(fulfilled).toHaveLength(1);
    expect(rejected).toHaveLength(1);

    const rejection = rejected[0] as PromiseRejectedResult;
    expect(rejection.reason).toBeInstanceOf(ReservationError);
    expect(rejection.reason.code).toBe(SEAT_ALREADY_RESERVED);
  });
});

// ─── AC4: Seat not found ─────────────────────────────────────────────────────

describe("AC4 — non-existent seat throws SEAT_NOT_FOUND", () => {
  it("throws ReservationError with code SEAT_NOT_FOUND when seat is null", async () => {
    const db = makeDb(null);

    await expect(reserveSeat("GHOST-99", "user-42", db)).rejects.toThrow(
      ReservationError
    );
    await expect(reserveSeat("GHOST-99", "user-42", db)).rejects.toMatchObject({
      code: SEAT_NOT_FOUND,
    });
  });

  it("does NOT call updateSeatStatus when seat is not found", async () => {
    const updateSpy = jest.fn();
    const db = makeDb(null, true, updateSpy);

    await expect(reserveSeat("GHOST-99", "user-42", db)).rejects.toThrow();
    expect(updateSpy).not.toHaveBeenCalled();
  });
});

